    # Example 1: '06-Oct-2143' -> 'Oct 43'
    if re.fullmatch(r'\d{2}-[A-Z]{3}-\d{4}', x):
        return f"{first_word(x).upper()} {number_2dp(number(x, 4))}"

    # Example 2: 'Mar 30 2002' -> 'Mar 02'
    if re.fullmatch(r'[A-Z]{3} \d{2} \d{4}', x):
        return f"{first_word(x).upper()} {number_2dp(number(x, 4))}"

    # Example 3: '01311846' -> 'Jan 46'
    if re.fullmatch(r'\d{6}\d{2}', x):
        return f"{alpha(x, 3).upper()} {number_2dp(number(x, 2))}"

    # Example 4: '22 Apr 1953' -> 'Apr 53'
    if re.fullmatch(r'\d{2} [A-Z]{3} \d{4}', x):
        return f"{first_word(x).upper()} {number_2dp(number(x, 4))}"

    # Default case
    return x

