def transform(row):
    import re
    time_str = row[0]
    if re.match(r'^\d{1,2}:\d{2}:\d{2}\s[AP]M$', time_str):
        hour_str, minute_str, second_str = time_str.split()
        hour = int(hour_str.split(':')[0])
        if hour >= 12:
            period = 'PM'
            hour -= 12
        else:
            period = 'AM'
            if hour == 0:
                hour = 12
        return f"{hour}:{minute_str} {period}"
    return time_str

