import re
import datetime

def transform(row):
    time_str = row[0]
    # Parse the time string into a datetime object
    try:
        time_obj = datetime.datetime.strptime(time_str, "%I:%M:%S %p")
    except ValueError:
        # If parsing fails, try a different format
        try:
            time_obj = datetime.datetime.strptime(time_str, "%I:%M:%S%p")
        except ValueError:
            # If still fails, return the original string
            return time_str

    # Format the time as 24-hour format with AM/PM
    return time_obj.strftime("%I:%M %p")
