import re
import datetime

def transform(row):
    time_str = row[0]
    # Use regex to match time format and parse into datetime object
    match = re.match(r'(\d{1,2}:\d{1,2}:\d{1,2}) ([AP]M)', time_str)
    if match:
        time_part = match.group(1)
        ampm = match.group(2)
        # Parse the time part into a datetime object
        try:
            time_obj = datetime.datetime.strptime(time_part, "%I:%M:%S")
        except ValueError:
            # If parsing fails, try a different format
            try:
                time_obj = datetime.datetime.strptime(time_part, "%H:%M:%S")
            except ValueError:
                # If still fails, return the original string
                return time_str

        # Format the time as 12-hour format with AM/PM
        return time_obj.strftime("%I:%M %p")
    else:
        # If the time string doesn't match the expected format, return the original string
        return time_str
