def transform(row):
    time_str = row[0]
    hour_str, minute_str, second_str = time_str.split(':')
    hour = int(hour_str)
    minute = int(minute_str)

    if 12 <= hour < 24:
        hour = hour - 12
    else:
        hour = hour

    if hour == 0:
        hour = 12

    if 0 <= minute < 60:
        minute = minute
    else:
        minute = 0

    return f"{hour}pm" if hour != 12 else "12pm" if hour == 12 else f"{hour}pm"

