    # Extract the area code from the phone number pattern
    phone_pattern = r'\((\d{3})\s?\d{3}[-]?\d{4}'
    phone_match = re.search(phone_pattern, row[0])
    if phone_match:
        return phone_match.group(1)
    return ''
