def transform(row):
    import re
    import math
    import datetime
    import calendar

    # Extract the phone number part from the input string
    phone_pattern = r'\((\d{3})\s?\d{3}-\d{4}'
    phone_match = re.search(phone_pattern, row[0])

    if phone_match:
        # Extract the area code (first 3 digits)
        return phone_match.group(1)
    else:
        # Fallback: extract the first 3 digits from the phone number part
        phone_number_pattern = r'\d{3}\s?\d{3}-\d{4}'
        phone_number_match = re.search(phone_number_pattern, row[0])
        if phone_number_match:
            return phone_number_match.group(0)[:3]
        else:
            return ''

