def transform(row):
    # Extract the first word
    first_word = row[0].split()[0]

    # Check if the first word is a number
    if re.fullmatch(r'\d+', first_word):
        # Extract the last word
        last_word = row[0].split()[-1]

        # Check if the last word contains a number and 'g' or 'ml'
        if re.search(r'[\d]+[gGmlML]', last_word):
            # Extract the number and unit
            match = re.search(r'(\d+)[gGmlML]', last_word)
            if match:
                return match.group(0)

    # Check if the row contains a number and 'g' or 'ml'
    if re.search(r'[\d]+[gGmlML]', row[0]):
        # Extract the number and unit
        match = re.search(r'(\d+)[gGmlML]', row[0])
        if match:
            return match.group(0)

    # If no match found, return 'N/A'
    return 'N/A'

